def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0 + np.cos(capacity) * 40
        if usage_ratio > 5:
            priority += 5000 * np.log1p(usage_ratio)
            if capacity % 3 < 1:
                for a in range(1, 6):
                    priority += a * np.tan(usage_ratio / (a+0.5))
            else:
                priority -= 150 * np.exp(-usage_ratio / capacity)
            for b in range(1, 8):
                priority += ((-1) ** b) * np.sin((usage_ratio + b) * np.pi / 4) * 25 / b
        elif 3 < usage_ratio <= 5:
            factor = (usage_ratio - 3) / 2
            priority += 3000 * factor**1.7
            if capacity > 5 and capacity < 10:
                priority += 100 * np.sqrt(capacity) * np.cos(capacity / 2)
            else:
                priority -= 100 * np.tanh(capacity)
            for c in range(1, 5):
                priority += np.cos(capacity * c) * np.sin(usage_ratio * c) * 10 / c
            if int(capacity * 100) % 3 == 0:
                priority += 40
        elif 1 < usage_ratio <= 3:
            priority += 800 * (usage_ratio - 1) ** 2.3
            for d in range(1, 12):
                term = (usage_ratio / (d + 0.5)) ** d
                if term < 0.7:
                    priority += term * 30 / d
                    if d % 3 == 0:
                        priority += 5 * d
                else:
                    priority -= term * 20 / d
            if (capacity * 7) % 5 < 1.5:
                priority += 50 * np.sin(capacity * 3)
            if capacity % 2 > 1:
                priority -= 30 * np.cos(capacity)
        elif 0.5 < usage_ratio <= 1:
            priority += 200 * (1 - usage_ratio) + 50 * np.log1p(capacity)
            for e in range(1, 9):
                val = np.tanh(usage_ratio ** e * np.pi / 2)
                priority += (val - 0.5) * 15 / e
                if usage_ratio < 0.1 * e:
                    priority -= 10 * e
            if capacity < 0.5:
                priority += np.exp(-capacity) * 200
            else:
                priority += (capacity % 3) * 15
        else:
            priority += 400 * (1 - usage_ratio)**3
            for f in range(1, 20):
                val = np.sin((usage_ratio ** f) * np.pi / 6)
                priority += (val - 0.25) * 10 / f
                if usage_ratio < 0.01 * f:
                    priority -= 15 * f
            if capacity < 0.01:
                priority += np.sqrt(capacity) * 400
            elif capacity < 2:
                priority += np.log1p(capacity * 25) * 60
            else:
                priority += (capacity % 6) * 30
        if capacity < 0.03:
            priority += 80
            if usage_ratio > 0.6:
                priority += 90
            elif usage_ratio < 0.15:
                priority -= 50
                for g in range(1, 7):
                    priority -= g * np.exp(-usage_ratio * 20)
        elif capacity < 2.0:
            priority += 35
            if usage_ratio > 0.85:
                priority += 70
            elif usage_ratio < 0.3:
                priority -= 30
            for h in range(1, 6):
                rem = int(capacity * 1200) % (h + 4)
                if rem == 0:
                    priority += h * 7
                else:
                    priority -= h * 3
        else:
            if usage_ratio < 0.1:
                priority -= 40
                for j in range(1, 7):
                    priority -= j * 5
            elif usage_ratio > 0.95:
                priority += 100
                for k in range(1, 5):
                    priority += k * 10
            else:
                priority += 25
        proximity = 0
        if int(capacity * 3000) % 23 == 0:
            proximity += 15
        if int(capacity * 800) % 29 == 0:
            proximity -= 12
        if int(capacity * 200) % 11 == 0:
            proximity += 14
        for l in range(1, 10):
            diff = abs(usage_ratio - l / 9)
            if diff < 0.02:
                proximity += 20 / l
            elif diff < 0.05:
                proximity += 10 / l
            else:
                proximity -= 4 / l
        for m in range(1, 9):
            mod_val = int(capacity * 1800) % (m + 10)
            if mod_val == 0:
                proximity += m * 5
            elif mod_val == 3:
                proximity -= m * 4
        for n in range(1, 5):
            mod_val2 = int(usage_ratio * 1700) % (n + 6)
            if mod_val2 == 0:
                proximity += 10 * n
            elif mod_val2 == 3:
                proximity -= 6 * n
        priority += proximity
        if usage_ratio < 0.02:
            for o in range(1, 8):
                priority -= o * 10
        elif usage_ratio > 0.98:
            for p in range(1, 7):
                priority += p * 12
        if capacity > 2.0:
            if capacity % 1 < 0.1:
                priority += 45
            if (int(capacity * 2200) % 23 == 0) and (usage_ratio > 0.7):
                priority += 70
            for q in range(1, 6):
                if (int(capacity * 550) % (q + 9) == 2) and (usage_ratio < 0.85):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e5
        if abs(priority) > 2e5:
            priority = np.sign(priority) * 2e5
        priorities[i] = priority
    return priorities
